class Solution {
    public String strWithout3a3b(int a, int b) {
        StringBuilder sb = new StringBuilder();
        while (a > 0 || b > 0) {
            if (a > b && a > 1) {
                sb.append("aa");
                a -= 2;
            } else if (b > a) {
                sb.append("bb");
                b -= 2;
            } else if (a >= b) {
                sb.append("a");
                a--;
            } else {
                sb.append("b");
                b--;
            }
        }
        return sb.toString();
    }
}
```

